const intent = $json.intent || '';
const params = $json.intentParams || {};
const GOOGLE_API_KEY = $env.GOOGLE_API_KEY || '';
const accessToken = $env.GOOGLE_ACCESS_TOKEN || '';

if (!GOOGLE_API_KEY && !accessToken) {
  return [{ json: { ...$json, responseText: '⚠️ Google API credentials not configured.', success: false } }];
}

let endpoint, body, method = 'GET';
const spreadsheetId = params.spreadsheet_id || params.id;

if (intent === 'sheets_read') {
  const range = params.range || 'Sheet1!A1:C10';
  endpoint = `https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}/values/${encodeURIComponent(range)}`;
} else if (intent === 'sheets_write') {
  const range = params.range || 'Sheet1!A1';
  endpoint = `https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}/values/${encodeURIComponent(range)}`;
  method = 'PUT';
  body = { values: params.values || [[]] };
} else if (intent === 'sheets_create') {
  endpoint = 'https://sheets.googleapis.com/v4/spreadsheets';
  method = 'POST';
  body = { properties: { title: params.title || 'New Spreadsheet' } };
} else {
  return [{ json: { ...$json, responseText: '❓ Unknown Sheets intent: ' + intent, success: false } }];
}

if (!spreadsheetId && intent !== 'sheets_create') {
  return [{ json: { ...$json, responseText: '❗ Spreadsheet ID required.', success: false } }];
}

return [{ json: { ...$json, apiEndpoint: endpoint, apiBody: body, apiMethod: method, range: params.range } }];

const values = $json.values;
if ($json.spreadsheetId && $json.properties) {
  const url = `https://docs.google.com/spreadsheets/d/${$json.spreadsheetId}/edit`;
  return [{ json: { ...$input.item.json, responseText: `📊 Spreadsheet created!

<b>${$json.properties.title}</b>

🔗 ${url}`, success: true } }];
}
if (values) {
  let text = `📊 Data (${$json.range || 'unknown range'}):

`;
  values.forEach(row => {
    text += row.join(' | ') + '\n';
  });
  return [{ json: { ...$input.item.json, responseText: text, success: true } }];
}
if ($json.updatedCells !== undefined) {
  return [{ json: { ...$input.item.json, responseText: `✅ ${$json.updatedCells} cell(s) updated.`, success: true } }];
}
return [{ json: { ...$input.item.json, responseText: `📊 Sheets operation completed.`, success: true } }];
